external_knowledge:
- 'Average game attendance' is calculated by summing up the attendance for each game in a season and then dividing by the total number of games in that season;
- 'Refereed' implies that Marc Davis was involved in the game as one of the three referees (referee_1, referee_2, or referee_3);
- 'Average attendance exceeded 50,000' means the calculated average attendance for a season is greater than 50,000.

sql:
SELECT review_type, review_outcome
FROM review_decisions
WHERE review_outcome = 'Upheld';

SELECT AVG(attendance) AS average_attendance
FROM games
WHERE referee_1 = 'Marc Davis' OR referee_2 = 'Marc Davis' OR referee_3 = 'Marc Davis';

SELECT COUNT(decision) AS total_upheld_decisions
FROM review_decisions
WHERE decision = 'Upheld';
